args.sparql:
SELECT ?work ?workLabel WHERE {
  wd:Q745 wdt:P50 ?work;
    wdt:P50 ?author.
  ?work wdt:P31 wd:Q571.
  ?work wdt:P577 ?workDate.
  wd:Q106179591 wdt:P577 ?oliverDate.
  FILTER(?workDate < ?oliverDate)
  ?work rdfs:label ?workLabel.
  FILTER(LANG(?workLabel) = 'en')
} ORDER BY DESC(?workDate) LIMIT 1

SELECT ?work ?workLabel WHERE {
  wd:Q745 wdt:P50 ?work.
  ?work wdt:P31 wd:Q571.
  ?work wdt:P577 ?workDate.
  {
    SELECT ?oliverDate WHERE {
      wd:Q745 wdt:P50 ?oliver.
      ?oliver rdfs:label 'Oliver Twist'@en.
      ?oliver wdt:P577 ?oliverDate.
    }
  }
  FILTER(?workDate < ?oliverDate)
  ?work rdfs:label ?workLabel.
  FILTER(LANG(?workLabel) = 'en')
} ORDER BY DESC(?workDate) LIMIT 1
